AppBar:
[ M3e.appBar [ M3e.size M3e.Value.medium ] []
    , M3e.appBar [ M3e.size M3e.Value.large ] []
    ]

Button:
[ M3e.button [ M3e.variant M3e.Value.tonal ] [ M3e.slotIcon (M3e.icon [ M3e.name "send" ] []), M3e.slotDefault (Kit.text "Send") ]
    , M3e.button [ M3e.variant M3e.Value.tonal ] [ M3e.slotTrailingIcon (M3e.icon [ M3e.name "open_in_new_window" ] []), M3e.slotDefault (Kit.text "Open") ]
    ]

[ M3e.button [ M3e.variant M3e.Value.filled, M3e.disabled True ] [ M3e.slotDefault (Kit.text "Disabled") ]
    , M3e.button [ M3e.variant M3e.Value.filled, M3e.disabledInteractive True ] [ M3e.slotDefault (Kit.text "Disabled Interactive") ]
    ]

Chips:
[ M3e.chip [] [ M3e.slotDefault (Kit.text "Outlined") ]
    , M3e.chip [ M3e.variant M3e.Value.elevated ] [ M3e.slotDefault (Kit.text "Elevated") ]
    ]

[ M3e.assistChip [] [ M3e.slotDefault (Kit.text "Outlined Assist") ]
    , M3e.assistChip [ M3e.variant M3e.Value.elevated ] [ M3e.slotDefault (Kit.text "Elevated Assist") ]
    ]

[ M3e.assistChip [ M3e.disabled True ] [ M3e.slotDefault (Kit.text "Disabled") ]
    , M3e.assistChip [ M3e.disabledInteractive True ] [ M3e.slotDefault (Kit.text "Disabled Interactive") ]
    ]

[ M3e.filterChipSet [ M3e.Aria.label "Filter by topic", M3e.hideSelectionIndicator True ] (M3e.FilterChipSet.children [ M3e.filterChip [] [ M3e.slotDefault (Kit.text "Design") ], M3e.filterChip [] [ M3e.slotDefault (Kit.text "Accessibility") ], M3e.filterChip [] [ M3e.slotIcon (M3e.icon [ M3e.name "motion_photos_on" ] []), M3e.slotDefault (Kit.text "Motion") ], M3e.filterChip [] [ M3e.slotIcon (M3e.icon [ M3e.name "description" ] []), M3e.slotDefault (Kit.text "Documentation") ] ])
    , Kit.text ">"
    ]

[ M3e.suggestionChip [] [ M3e.slotDefault (Kit.text "Outlined Suggestion") ]
    , M3e.suggestionChip [ M3e.variant M3e.Value.elevated ] [ M3e.slotDefault (Kit.text "Elevated Suggestion") ]
    ]

[ M3e.suggestionChip [ M3e.disabled True ] [ M3e.slotDefault (Kit.text "Disabled") ]
    , M3e.suggestionChip [ M3e.disabledInteractive True ] [ M3e.slotDefault (Kit.text "Disabled Interactive") ]
    ]

Fab:
[ M3e.fab [ M3e.disabled True ] [ M3e.slotDefault (M3e.icon [ M3e.name "add" ] []) ]
    , M3e.fab [ M3e.disabledInteractive True ] [ M3e.slotDefault (M3e.icon [ M3e.name "add" ] []) ]
    ]

IconButton:
[ M3e.iconButton [ M3e.variant M3e.Value.tonal, M3e.width M3e.Value.narrow ] [ M3e.slotDefault (M3e.icon [ M3e.name "add" ] []) ]
    , M3e.iconButton [ M3e.variant M3e.Value.tonal, M3e.width M3e.Value.wide ] [ M3e.slotDefault (M3e.icon [ M3e.name "add" ] []) ]
    ]

[ M3e.iconButton [ M3e.variant M3e.Value.filled, M3e.disabled True ] [ M3e.slotDefault (M3e.icon [ M3e.name "check" ] []) ]
    , M3e.iconButton [ M3e.variant M3e.Value.filled, M3e.disabledInteractive True ] [ M3e.slotDefault (M3e.icon [ M3e.name "check" ] []) ]
    ]

RadioGroup:
[ Native.node Html.label [] [ Kit.text "Select an option" ]
    , M3e.radioGroup [] [ M3e.slotDefault (Native.node Html.label [] [ M3e.radio [ M3e.value "1" ] [], Kit.text "Option 1" ]) ]
    ]

[ Native.node Html.label [] [ Kit.text "Select an option" ]
    , M3e.radioGroup [] [ M3e.slotDefault (Native.node Html.label [] [ M3e.radio [ M3e.disabled True, M3e.value "1" ] [], Kit.text "Option 1" ]) ]
    ]

[ Native.node Html.label [] [ Kit.text "Select an option" ]
    , M3e.radioGroup [ M3e.disabled True ] [ M3e.slotDefault (Native.node Html.label [] [ M3e.radio [ M3e.value "1" ] [], Kit.text "Option 1" ]) ]
    ]

[ Native.node Html.label [] [ Kit.text "Select an option" ]
    , M3e.radioGroup [ M3e.required True ] [ M3e.slotDefault (Native.node Html.label [] [ M3e.radio [ M3e.value "1" ] [], Kit.text "Option 1" ]) ]
    ]

Switch:
[ M3e.switch [ M3e.icons M3e.Value.selected, M3e.checked True ] []
    , M3e.switch [ M3e.icons M3e.Value.both ] []
    ]

Theme:
[ M3e.theme [ M3e.motion M3e.Value.standard ] []
    , M3e.theme [ M3e.motion M3e.Value.expressive ] []
    ]

Toolbar:
[ M3e.toolbar [ M3e.variant M3e.Value.standard ] (M3e.Toolbar.children [ M3e.iconButton [] [ M3e.slotDefault (M3e.icon [ M3e.name "arrow_back" ] []) ], M3e.iconButton [] [ M3e.slotDefault (M3e.icon [ M3e.name "arrow_forward" ] []) ], M3e.iconButton [ M3e.width M3e.Value.wide, M3e.variant M3e.Value.filled ] [ M3e.slotDefault (M3e.icon [ M3e.name "add" ] []) ], M3e.iconButton [] [ M3e.slotDefault (M3e.icon [ M3e.name "picture_in_picture" ] []) ], M3e.iconButton [] [ M3e.slotDefault (M3e.icon [ M3e.name "more_vert" ] []) ] ])
    , M3e.toolbar [ M3e.variant M3e.Value.vibrant ] []
    ]

Tooltip:
[ M3e.iconButton [] [ M3e.slotDefault (M3e.icon [ M3e.name "arrow_back" ] []) ]
    , M3e.tooltip [ M3e.for "button" ] [ M3e.slotDefault (Kit.text "Go Back") ]
    ]

[ M3e.iconButton [] [ M3e.slotDefault (M3e.icon [ M3e.name "arrow_back" ] []) ]
    , M3e.tooltip [ M3e.for "button", M3e.showDelay 0, M3e.hideDelay 200 ] [ M3e.slotDefault (Kit.text "Go Back") ]
    ]

[ M3e.iconButton [] [ M3e.slotDefault (M3e.icon [ M3e.name "arrow_back" ] []) ]
    , M3e.tooltip [ M3e.for "button", M3e.disabled True ] [ M3e.slotDefault (Kit.text "Go Back") ]
    ]

[ M3e.iconButton [] [ M3e.slotDefault (M3e.icon [ M3e.name "settings" ] []) ]
    , M3e.richTooltip [ M3e.for "button" ] [ M3e.slotSubhead (Native.span [] [ Kit.text "New settings available" ]), M3e.slotDefault (Kit.text "Now you can adjust the uploaded image quality, and upgrade your available storage space.") ]
    ]
